diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 76020d2b1dbf..4bbd2f2c8d28 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7416,6 +7416,7 @@ Instruction *InstCombinerImpl::foldICmpCommutative(CmpPredicate Pred,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   bool Changed = false;
   const SimplifyQuery Q = SQ.getWithInstruction(&I);
@@ -7435,6 +7436,27 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   if (Value *V = simplifyICmpInst(I.getCmpPredicate(), Op0, Op1, Q))
     return replaceInstUsesWith(I, V);

+  // Fold equality/inequality compares of trunc nuw-to-i1 back to the original
+  // wider operands:
+  //   icmp eq/ne (trunc nuw X to i1), (trunc nuw Y to i1)
+  //     -->
+  //   icmp eq/ne X, Y
+  //
+  // trunc nuw to i1 implies the source operand is in {0,1}, so the truncation
+  // is value-preserving and comparing the truncated values is equivalent to
+  // comparing the original values.
+  if (I.isEquality() && Op0->getType()->isIntOrIntVectorTy(1)) {
+    auto *Trunc0 = dyn_cast<TruncInst>(Op0);
+    auto *Trunc1 = dyn_cast<TruncInst>(Op1);
+    if (Trunc0 && Trunc1 && Trunc0->hasNoUnsignedWrap() &&
+        Trunc1->hasNoUnsignedWrap()) {
+      Value *X = Trunc0->getOperand(0);
+      Value *Y = Trunc1->getOperand(0);
+      if (X->getType() == Y->getType())
+        return new ICmpInst(I.getPredicate(), X, Y);
+    }
+  }
+
   // Comparing -val or val with non-zero is the same as just comparing val
   // ie, abs(val) != 0 -> val != 0
   if (I.getPredicate() == ICmpInst::ICMP_NE && match(Op1, m_Zero())) {
@@ -7745,6 +7767,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   return Changed ? &I : nullptr;
 }

+
 /// Fold fcmp ([us]itofp x, cst) if possible.
 Instruction *InstCombinerImpl::foldFCmpIntToFPConst(FCmpInst &I,
                                                     Instruction *LHSI,

